// 终端状态的判断
export type TaskStatus =
  | 'pending'
  | 'running'
  | 'completed'
  | 'failed'
  | 'killed'

export function isTerminalTaskStatus(status: TaskStatus): boolean {
  return status === 'completed' || status === 'failed' || status === 'killed'
}

// 任务清理的完全条件：必须终端 且 已通知
function canEvictTask(task: TaskState): boolean {
  return isTerminalTaskStatus(task.status) && task.notified
}
